import json, numpy as np

# Compare Round 1 and Round 2 metrics
print("=== Cross-Round Comparison ===\n")

# Round 1: run_1780250271
for label, run_id in [("Round 1 (final)", "run_1780250271"), ("Round 2 Run1", "run_1780281634"), 
                        ("Round 2 Run2", "run_1780284483"), ("Round 2 Run3", "run_1780285930"),
                        ("Round 2 (final)", "run_1780283875")]:
    path = f'rllm_train/output/runs/{run_id}/verl_metrics.jsonl'
    try:
        with open(path) as f:
            lines = f.readlines()

        scores = []
        kls = []
        ents = []
        cfs = []
        gns = []
        for line in lines:
            if not line.strip():
                continue
            d = json.loads(line)
            data = d.get('data', {})
            s = data.get('critic/score/mean')
            kl = data.get('actor/ppo_kl')
            ent = data.get('actor/entropy')
            cf = data.get('actor/pg_clipfrac')
            gn = data.get('actor/grad_norm')
            if s is not None: scores.append(s)
            if kl is not None: kls.append(kl)
            if ent is not None: ents.append(ent)
            if cf is not None: cfs.append(cf)
            if gn is not None: gns.append(gn)

        n = len(lines)
        print(f"{label} ({run_id}): {n} steps")
        if scores:
            print(f"  Score: mean={np.mean(scores):.4f}, std={np.std(scores):.4f}, "
                  f"first={scores[0]:.4f}, last={scores[-1]:.4f}, "
                  f"trend={'↑' if scores[-1] > scores[0] else '↓'}")
        if kls:
            print(f"  KL: mean={np.mean(kls):.6f}, max={np.max(kls):.6f}")
        if ents:
            print(f"  Entropy: {ents[0]:.4f} → {ents[-1]:.4f}")
        if cfs:
            print(f"  Clipfrac: mean={np.mean(cfs):.4f}, max={np.max(cfs):.4f}")
        if gns:
            print(f"  Grad norm: mean={np.mean(gns):.4f}, max={np.max(gns):.4f}")
        print()
    except Exception as e:
        print(f"{label} ({run_id}): ERROR - {e}\n")
PYEOF

